func (r *NodeAutoscalingReconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result
{
    defer r.Finalize()

    if req.StatusCode != k8s.io.status_codes.StatusCodeOk {
        req.StatusCode = k8s.io.status_codes.StatusCodeOk
        return ctrlReturnValue{Code: k8s.io.status_codes.StatusCodeOk, Details: "Error reconciling resource"}
    }

    // Update node labels based on current node status
    if req.Method == "GET" || req.Method == "HEAD" {
        return r.GetAll()
    }

    if req.Method == "POST" {
        return r.AllCreate()
    }

    if req.Method == "PUT" || req.Method == "ATCH" {
        return r.AllUpdate()
    }

    if req.Method == "DELETE" {
        return r.AllDelete()
    }

    return ctrlReturnValue{Code: k8s.io.status_codes.StatusCodeBadRequest, Details: "Unknown HTTP method"}
}

func (r *NodeAutoscalingReconciler) GetAll() (ctrl.ResponseList) {
    _, list := r.client.KaryList()
    return list
}

func (r *NodeAutoscalingReconciler) AllCreate() (ctrl.ResponseList) {
    _, cr := r.client.KaryCreate([]NodeAutoscaling{})
    return cr
}

func (r *NodeAutoscalingReconciler) AllUpdate() (ctrl.ResponseList) {
    _, updateOp := r.client.KaryPatch([]NodeAutoscaling{})
    return updateOp
}

func (r *NodeAutoscalingReconciler) AllDelete() (ctrl.ResponseList) {
    _, deleteOp := r.client.KaryDelete(nil)
    return deleteOp
}

// This function is called by the client to update the resource
func (r *NodeAutoscalingReconciler) Update(nodeAutoscaling *NodeAutoscaling) (ctrl.Response) {
    err := r.client.KaryPatch([]*NodeAutoscaling{nodeAutoscaling}, err: r.client.NewError())
    return r.client.NewResponse(err)
}
